const page = `<!doctype html>
<html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<title>Rapido Dispatch Lab</title>
<style>
  :root{--ink:#121722;--muted:#657084;--line:#e4e8ee;--paper:#fff;--canvas:#f6f8fb;--yellow:#ffd63d;--green:#0c9f6a;--green-soft:#e7f7f0;--blue:#526df6;--blue-soft:#eef0ff;--amber:#a56200;--amber-soft:#fff4c4;--gray-soft:#f1f3f7}
  *{box-sizing:border-box}body{margin:0;background:var(--canvas);color:var(--ink);font-family:Inter,ui-sans-serif,system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}main{max-width:1120px;margin:auto;padding:42px 24px 70px}.brand{display:flex;align-items:center;gap:10px;font-size:18px;font-weight:900;letter-spacing:-.03em}.bolt{height:28px;width:28px;border-radius:8px;background:var(--yellow);display:grid;place-items:center;transform:rotate(-8deg)}.eyebrow{font-size:11px;letter-spacing:.12em;color:var(--muted);font-weight:800;text-transform:uppercase;margin-left:2px}h1{font-size:clamp(35px,5vw,59px);line-height:1.02;letter-spacing:-.055em;margin:24px 0 13px;max-width:720px}h1 mark{background:linear-gradient(90deg,var(--yellow) 0 88%,transparent 88%);background-repeat:no-repeat;background-size:100% 35%;background-position:0 88%;color:inherit;padding:0}.lede{margin:0 0 30px;max-width:690px;color:var(--muted);line-height:1.55}.grid{display:grid;grid-template-columns:minmax(0,1fr) minmax(340px,1fr);gap:20px}.panel{background:var(--paper);border:1px solid var(--line);border-radius:20px;padding:25px;box-shadow:0 10px 30px rgba(18,23,34,.04)}.panel h2{font-size:18px;letter-spacing:-.025em;margin:0}.subhead{font-size:13px;color:var(--muted);line-height:1.5;margin:7px 0 18px}.label{display:block;font-size:12px;font-weight:800;color:#4f5969;margin:16px 0 7px}input{width:100%;padding:13px 14px;border:1px solid #d7dce4;border-radius:10px;color:var(--ink);font:inherit;outline:0}input:focus{border-color:var(--blue);box-shadow:0 0 0 3px #526df622}.split{display:grid;grid-template-columns:1fr 1fr;gap:12px}.hint{font-size:12px;line-height:1.45;color:var(--muted);margin:10px 0 0}button{width:100%;margin-top:20px;padding:14px 17px;border:0;border-radius:11px;background:var(--ink);color:#fff;font:800 14px inherit;cursor:pointer}button:hover{background:#2b3444}button:disabled{opacity:.65;cursor:wait}.alert{display:none;color:#b42331;font-size:13px;margin:13px 0 0}.empty{min-height:355px;display:grid;place-items:center;text-align:center;padding:35px;border:1px dashed #d5dce6;border-radius:15px;color:var(--muted);line-height:1.6}.empty strong{display:block;color:var(--ink);margin-bottom:5px}.ride-card{display:none}.ride-top{display:flex;justify-content:space-between;gap:14px;padding-bottom:17px;border-bottom:1px solid var(--line)}.meta-label{font-size:11px;font-weight:800;letter-spacing:.08em;color:var(--muted);text-transform:uppercase}.destination{font-size:17px;font-weight:800;margin-top:5px}.tag{align-self:flex-start;border-radius:99px;background:var(--amber-soft);color:#755100;padding:7px 10px;font-size:11px;font-weight:900;letter-spacing:.05em;white-space:nowrap}.live-message{margin:16px 0 14px;font-size:14px;font-weight:700;line-height:1.45}.journey{list-style:none;margin:0;padding:0}.journey li{display:grid;grid-template-columns:26px 1fr;column-gap:11px;position:relative;padding:0 0 16px}.journey li:last-child{padding-bottom:3px}.journey li:not(:last-child):after{content:"";position:absolute;left:12px;top:25px;bottom:0;border-left:1px solid #d8dce3}.marker{grid-column:1;grid-row:1;width:25px;height:25px;border-radius:50%;background:var(--gray-soft);border:1px solid #dce1e8;color:var(--muted);display:grid;place-items:center;font-size:12px;font-weight:900;z-index:1}.stage-copy{grid-column:2;grid-row:1;padding-top:2px}.stage-title{display:block;font-size:14px;font-weight:800}.stage-tech{display:block;margin-top:2px;font-size:12px;line-height:1.35;color:var(--muted)}.journey li[data-state="done"] .marker{background:var(--green);color:#fff;border-color:var(--green)}.journey li[data-state="active"] .marker{background:var(--blue);color:#fff;border-color:var(--blue);box-shadow:0 0 0 5px #526df61a}.journey li[data-state="done"]:after{border-color:var(--green)}.driver{display:flex;gap:12px;align-items:center;margin:17px 0 0;padding:15px 0 0;border-top:1px solid var(--line)}.avatar{width:42px;height:42px;border-radius:13px;display:grid;place-items:center;font-weight:900}.driver b{display:block;font-size:14px}.small{font-size:12px;color:var(--muted);line-height:1.4}.explain{margin-top:20px;border-top:1px solid var(--line);padding-top:16px}.explain summary{cursor:pointer;font-size:13px;font-weight:850;list-style:none}.explain summary::-webkit-details-marker{display:none}.explain summary:before{content:"+";display:inline-grid;place-items:center;width:19px;height:19px;border-radius:50%;background:var(--blue-soft);color:var(--blue);margin-right:8px;font-weight:900}.explain[open] summary:before{content:"−"}.tech-flow{display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-top:15px}.tech-step{min-width:0;padding:11px;background:#f8f9fc;border:1px solid #edf0f4;border-radius:11px}.tech-number{display:block;font-size:11px;font-weight:900;color:var(--blue)}.tech-step strong{display:block;font-size:12px;line-height:1.3;margin:4px 0}.tech-step span{display:block;color:var(--muted);font-size:11px;line-height:1.35}.event-log{margin:16px 0 0;padding:0;list-style:none;border-top:1px solid var(--line)}.event-log li{position:relative;padding:12px 0 12px 18px;border-bottom:1px solid var(--line);font-size:13px;font-weight:700}.event-log li:before{content:"";position:absolute;left:0;top:17px;width:8px;height:8px;border-radius:50%;background:var(--green)}.event-log time{display:block;color:var(--muted);font-size:11px;font-weight:500;margin-top:2px}.footer-note{display:flex;align-items:center;gap:8px;margin-top:31px;color:var(--muted);font-size:12px}.pulse{height:9px;width:9px;border-radius:50%;background:var(--green);box-shadow:0 0 0 5px #0c9f6a1a}.guide{margin-top:21px;background:var(--ink);color:#eef2f8;border-radius:18px;padding:23px}.guide h2{margin:0 0 5px;color:var(--yellow);font-size:13px;text-transform:uppercase;letter-spacing:.1em}.guide p{margin:0 0 17px;color:#bdc6d6;font-size:13px;line-height:1.5}.guide-flow{display:grid;grid-template-columns:repeat(5,1fr);gap:9px}.guide-step{min-width:0}.guide-step b{display:grid;place-items:center;width:25px;height:25px;border-radius:50%;background:#273140;color:var(--yellow);font-size:11px;margin-bottom:7px}.guide-step strong{display:block;font-size:12px;line-height:1.35}.guide-step span{display:block;color:#aeb9c9;font-size:11px;line-height:1.38;margin-top:3px}@media(max-width:820px){.grid{grid-template-columns:1fr}.tech-flow,.guide-flow{grid-template-columns:1fr 1fr}.empty{min-height:250px}}@media(max-width:520px){main{padding:27px 15px 50px}.panel{padding:19px}.split,.tech-flow,.guide-flow{grid-template-columns:1fr}.ride-top{flex-direction:column}.tag{align-self:flex-start}}
</style></head><body><main>
  <div class="brand"><span class="bolt">↯</span> RAPIDO <span class="eyebrow">dispatch lab</span></div>
  <h1>Book a ride.<br><mark>See the system work.</mark></h1>
  <p class="lede">The rider sees clear progress. The coder can open one small panel to see exactly how PostgreSQL and Kafka move the request forward.</p>

  <section class="grid">
    <form class="panel" id="ride-form">
      <h2>Request an instant ride</h2>
      <p class="subhead">Try the complete request → dispatch → assignment journey.</p>
      <label class="label" for="name">Rider name</label><input id="name" required maxlength="80" value="Venkatesh">
      <label class="label" for="destination">Where to?</label><input id="destination" required maxlength="200" value="Indiranagar Metro">
      <div class="split"><div><label class="label" for="lat">Pickup latitude</label><input id="lat" type="number" step="any" required value="12.9716"></div><div><label class="label" for="lng">Pickup longitude</label><input id="lng" type="number" step="any" required value="77.5946"></div></div>
      <p class="hint">Demo pickup: Bangalore CBD, near the seeded driver fleet.</p>
      <button id="submit" type="submit">Find my Rapido</button><p class="alert" id="error" role="alert"></p>
    </form>

    <section class="panel" aria-live="polite">
      <h2>Your ride, explained</h2>
      <p class="subhead">One simple progress view for riders and coders.</p>
      <div class="empty" id="empty"><div><strong>Ready when you are</strong>Book a ride to see each dispatch step progress in real time.<br><span class="small">No page request waits for Kafka.</span></div></div>
      <div class="ride-card" id="ride-card">
        <div class="ride-top"><div><div class="meta-label">Destination</div><div class="destination" id="ride-destination"></div></div><span class="tag" id="ride-status">REQUESTED</span></div>
        <p class="live-message" id="live-message">Saving your request…</p>
        <ol class="journey" aria-label="Ride request progress">
          <li data-stage="saved" data-state="active"><span class="marker">1</span><div class="stage-copy"><span class="stage-title">Request saved</span><span class="stage-tech">PostgreSQL saved the ride and its outbox event together.</span></div></li>
          <li data-stage="published" data-state="waiting"><span class="marker">2</span><div class="stage-copy"><span class="stage-title">Dispatch notified</span><span class="stage-tech">Kafka carries <code>ride.requested.v1</code> to Dispatch.</span></div></li>
          <li data-stage="matching" data-state="waiting"><span class="marker">3</span><div class="stage-copy"><span class="stage-title" id="matching-title">Finding a nearby captain</span><span class="stage-tech" id="matching-tech">Dispatch compares available captain locations.</span></div></li>
          <li data-stage="assigned" data-state="waiting"><span class="marker">4</span><div class="stage-copy"><span class="stage-title" id="assigned-title">Waiting for an assignment</span><span class="stage-tech" id="assigned-tech">The screen updates after <code>ride.assigned.v1</code> arrives.</span></div></li>
        </ol>
        <div id="driver-slot"></div>
        <details class="explain" id="coder-lens"><summary>Coder’s lens: what is happening behind the screen?</summary><div class="tech-flow"><div class="tech-step"><span class="tech-number">01 · State</span><strong>Ride + outbox</strong><span>PostgreSQL transaction</span></div><div class="tech-step"><span class="tech-number">02 · Event</span><strong>Request sent</strong><span>Kafka topic</span></div><div class="tech-step"><span class="tech-number">03 · Decision</span><strong>Captain reserved</strong><span>Dispatch database</span></div><div class="tech-step"><span class="tech-number">04 · Projection</span><strong>Screen refreshed</strong><span>Ride read model</span></div></div></details>
        <ol class="event-log" id="timeline" aria-label="Received events"></ol>
      </div>
      <div class="footer-note"><span class="pulse"></span><span>Live state comes from the ride read model.</span></div>
    </section>
  </section>

  <section class="guide" aria-label="Implementation guide">
    <h2>How one click becomes a ride</h2><p>Use this as the easy mental model. PostgreSQL remembers the state; Kafka tells the next service what happened.</p>
    <div class="guide-flow"><div class="guide-step"><b>1</b><strong>Book</strong><span>Browser sends ride details.</span></div><div class="guide-step"><b>2</b><strong>Save</strong><span>Ride API commits ride + outbox.</span></div><div class="guide-step"><b>3</b><strong>Publish</strong><span>Relay publishes the request to Kafka.</span></div><div class="guide-step"><b>4</b><strong>Match</strong><span>Dispatch reserves the closest free captain.</span></div><div class="guide-step"><b>5</b><strong>Show</strong><span>Projection and timeline update the screen.</span></div></div>
  </section>
</main><script>
let rideID,timer;const $=id=>document.getElementById(id);const labels={REQUESTED:'REQUESTED',SEARCHING_DRIVER:'SEARCHING',DRIVER_ASSIGNED:'DRIVER ASSIGNED'};
function setStage(name,state){const item=document.querySelector('[data-stage="'+name+'"]');if(item)item.dataset.state=state;}
function setStageCopy(name,title,detail){$(name+'-title').textContent=title;$(name+'-tech').textContent=detail;}
function updateJourney(ride,activity){const requested=activity.some(item=>item.kind==='requested');const deferred=activity.some(item=>item.kind==='dispatch_deferred');const assigned=ride.status==='DRIVER_ASSIGNED';setStage('saved','done');setStage('published',requested?'done':'active');setStage('matching',assigned?'done':requested?'active':'waiting');setStage('assigned',assigned?'done':'waiting');if(assigned&&ride.driver){setStageCopy('matching','Captain reserved','Dispatch safely reserved '+ride.driver.name+' for this ride.');setStageCopy('assigned','Ride screen updated','Kafka carried the assignment; this read model refreshed the UI.');$('live-message').textContent=ride.driver.name+' is assigned. Your ride read model is up to date.';}else if(deferred||ride.status==='SEARCHING_DRIVER'){setStageCopy('matching','Waiting for a free captain','No captain is available now. Dispatch keeps this ride pending for another match.');setStageCopy('assigned','Waiting for an assignment','No assignment event has been produced yet.');$('live-message').textContent='No captain is free just now. Your request is safely saved and still waiting in Dispatch.';}else{setStageCopy('matching','Finding a nearby captain','Dispatch is comparing available captain locations.');setStageCopy('assigned','Waiting for an assignment','The screen updates after the assignment event arrives.');$('live-message').textContent='We saved your request and are finding a nearby captain.';}}
function renderDriver(driver){const slot=$('driver-slot');if(!driver){slot.replaceChildren();return;}const wrapper=document.createElement('div');wrapper.className='driver';const avatar=document.createElement('div');avatar.className='avatar';avatar.style.background=driver.color;avatar.textContent=driver.name.slice(0,1);const copy=document.createElement('div');const name=document.createElement('b');name.textContent=driver.name;const details=document.createElement('span');details.className='small';details.textContent=driver.vehicle_label+' · '+driver.phone;copy.append(name,details);wrapper.append(avatar,copy);slot.replaceChildren(wrapper);}
function renderTimeline(activity){const timeline=$('timeline');timeline.replaceChildren();activity.forEach(item=>{const row=document.createElement('li');const title=document.createElement('span');title.textContent=item.title;const time=document.createElement('time');time.textContent=new Date(item.occurred_at).toLocaleTimeString();row.append(title,time);timeline.append(row);});}
$('ride-form').addEventListener('submit',async event=>{event.preventDefault();$('error').style.display='none';$('submit').disabled=true;$('submit').textContent='Saving request…';try{const response=await fetch('/api/rides',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({rider_name:$('name').value,pickup_latitude:Number($('lat').value),pickup_longitude:Number($('lng').value),destination:$('destination').value})});const ride=await response.json();if(!response.ok)throw Error(ride.error||'Request failed');rideID=ride.id;$('empty').style.display='none';$('ride-card').style.display='block';setStage('saved','active');setStage('published','waiting');setStage('matching','waiting');setStage('assigned','waiting');$('live-message').textContent='Ride saved. Preparing the dispatch request…';renderDriver(null);renderTimeline([]);poll();clearInterval(timer);timer=setInterval(poll,1000);}catch(error){$('error').textContent=error.message;$('error').style.display='block';}finally{$('submit').disabled=false;$('submit').textContent='Find my Rapido';}});
async function poll(){if(!rideID)return;try{const [rideResponse,activityResponse]=await Promise.all([fetch('/api/rides/'+rideID),fetch('/api/rides/'+rideID+'/activity')]);if(!rideResponse.ok)return;const ride=await rideResponse.json();const activity=activityResponse.ok?await activityResponse.json():[];$('ride-destination').textContent=ride.destination;$('ride-status').textContent=labels[ride.status]||ride.status;updateJourney(ride,activity);renderDriver(ride.driver);renderTimeline(activity);}catch(_){}}
</script></body></html>`
